function Login() {
  const navigate = useNavigate();
  const [data, setData] = useState({ username: '', password: '' });

  const handleChange = (e) =>
    setData({ ...data, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:8080/login', data, { withCredentials: true });
      toast.success(res.data.message);
      setData({ username: '', password: '' });
      navigate('/Dashboard');
    } catch (err) {
      toast.error("Login Failed!");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-r from-[#e0f2ff] to-[#f4f8ff]">
      {/* Left side (SVG animation) */}
      <div className="hidden md:flex w-1/2 items-center justify-center p-8">
        <DoctorIllustration />
      </div>

      {/* Right side (Login form) */}
      <div className="flex w-full md:w-1/2 items-center justify-center p-8">
        <form
          className="bg-white rounded-2xl shadow-lg shadow-blue-200 w-[330px] px-8 py-10 flex flex-col items-center"
          onSubmit={handleSubmit}
        >
          <h2 className="text-3xl font-bold mb-6 text-center">
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-700 via-purple-700 to-pink-600">
              Welcome Back!
            </span>
          </h2>
          <input
            type="text"
            value={data.username}
            name="username"
            placeholder="Email or Username"
            required
            onChange={handleChange}
            className="mb-4 w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-purple-400 transition"
          />
          <input
            type="password"
            value={data.password}
            name="password"
            placeholder="Password"
            required
            onChange={handleChange}
            className="mb-6 w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-purple-400 transition"
          />
          <button
            type="submit"
            className="w-full py-3 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-700 hover:to-blue-700 text-white font-semibold rounded-full shadow-lg transition duration-300 ease-in-out"
          >
            Sign In
          </button>
          <p className="mt-4 text-sm text-gray-700 text-center">
            New user?{' '}
            <Link to="/Register" className="text-purple-700 font-bold hover:underline">
              Register here
            </Link>
          </p>
        </form>
      </div>
    </div>
  );
}

export default Login;
